// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 1000
#define MAX_MOVES MAX_N * (MAX_N + 7)

char maze[MAX_N][MAX_N + 1];
char moves[MAX_MOVES + 1];
int visited[MAX_N][MAX_N];
int moveCount;

void bfs(int x, int y) {
    int queueX[MAX_N * MAX_N], queueY[MAX_N * MAX_N], queueSize = 0;
    queueX[queueSize] = x;
    queueY[queueSize] = y;
    queueSize++;
    visited[x][y] = 1;

    while (queueSize > 0) {
        x = queueX[0];
        y = queueY[0];
        for (int i = 1; i < queueSize; i++) {
            queueX[i - 1] = queueX[i];
            queueY[i - 1] = queueY[i];
        }
        queueSize--;

        if (x > 1 && maze[x - 1][y] == '.' && !visited[x - 1][y]) {
            queueX[queueSize] = x - 1;
            queueY[queueSize] = y;
            queueSize++;
            visited[x - 1][y] = 1;
            moves[moveCount++] = 'U';
        }
        if (x < MAX_N && maze[x + 1][y] == '.' && !visited[x + 1][y]) {
            queueX[queueSize] = x + 1;
            queueY[queueSize] = y;
            queueSize++;
            visited[x + 1][y] = 1;
            moves[moveCount++] = 'D';
        }
        if (y > 1 && maze[x][y - 1] == '.' && !visited[x][y - 1]) {
            queueX[queueSize] = x;
            queueY[queueSize] = y - 1;
            queueSize++;
            visited[x][y - 1] = 1;
            moves[moveCount++] = 'L';
        }
        if (y < MAX_N && maze[x][y + 1] == '.' && !visited[x][y + 1]) {
            queueX[queueSize] = x;
            queueY[queueSize] = y + 1;
            queueSize++;
            visited[x][y + 1] = 1;
            moves[moveCount++] = 'R';
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        for (int i = 1; i <= N; i++) {
            scanf("%s", maze[i] + 1);
        }
        moveCount = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                visited[i][j] = 0;
            }
        }
        bfs(1, 1);
        printf("%s\n", moves);
    }
    return 0;
}

