#include <iostream>
#include <queue>
#include <vector>
#include <string>
using namespace std;
#define MAX_N 1000
#define MAX_MOVES MAX_N * (MAX_N + 7)

struct Point {
    int x, y;
};

char maze[MAX_N][MAX_N + 1];
char moves[MAX_MOVES + 1];
int visited[MAX_N][MAX_N];
int moveCount;

void bfs(int x, int y) {
    queue<Point> q;
    q.push({x, y});
    visited[x][y] = 1;

    while (!q.empty()) {
        x = q.front().x;
        y = q.front().y;
        q.pop();

        if (x > 1 && maze[x - 1][y] == '.' && !visited[x - 1][y]) {
            q.push({x - 1, y});
            visited[x - 1][y] = 1;
            moves[moveCount++] = 'U';
        }
        if (x < MAX_N && maze[x + 1][y] == '.' && !visited[x + 1][y]) {
            q.push({x + 1, y});
            visited[x + 1][y] = 1;
            moves[moveCount++] = 'D';
        }
        if (y > 1 && maze[x][y - 1] == '.' && !visited[x][y - 1]) {
            q.push({x, y - 1});
            visited[x][y - 1] = 1;
            moves[moveCount++] = 'L';
        }
        if (y < MAX_N && maze[x][y + 1] == '.' && !visited[x][y + 1]) {
            q.push({x, y + 1});
            visited[x][y + 1] = 1;
            moves[moveCount++] = 'R';
        }
    }
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        for (int i = 1; i <= N; i++) {
            cin >> maze[i];
        }
        moveCount = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                visited[i][j] = 0;
            }
        }
        bfs(1, 1);
        cout << moves << endl;
    }
    return 0;
}

