// COMPLETE, COMPILABLE Java code
import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    static final int MAX_N = 1000;
    static final int MAX_MOVES = MAX_N * (MAX_N + 7);
    static char[][] maze = new char[MAX_N + 1][MAX_N + 1];
    static char[] moves = new char[MAX_MOVES + 1];
    static int[][] visited = new int[MAX_N + 1][MAX_N + 1];
    static int moveCount;

    static class Point {
        int x, y;
        Point(int x, int y) {
            this.x = x;
            this.y = y;
        }
    }

    static void bfs(int x, int y) {
        Queue<Point> q = new LinkedList<>();
        q.add(new Point(x, y));
        visited[x][y] = 1;

        while (!q.isEmpty()) {
            x = q.peek().x;
            y = q.peek().y;
            q.poll();

            if (x > 1 && maze[x - 1][y] == '.' && visited[x - 1][y] == 0) {
                q.add(new Point(x - 1, y));
                visited[x - 1][y] = 1;
                moves[moveCount++] = 'U';
            }
            if (x < MAX_N && maze[x + 1][y] == '.' && visited[x + 1][y] == 0) {
                q.add(new Point(x + 1, y));
                visited[x + 1][y] = 1;
                moves[moveCount++] = 'D';
            }
            if (y > 1 && maze[x][y - 1] == '.' && visited[x][y - 1] == 0) {
                q.add(new Point(x, y - 1));
                visited[x][y - 1] = 1;
                moves[moveCount++] = 'L';
            }
            if (y < MAX_N && maze[x][y + 1] == '.' && visited[x][y + 1] == 0) {
                q.add(new Point(x, y + 1));
                visited[x][y + 1] = 1;
                moves[moveCount++] = 'R';
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            for (int i = 1; i <= N; i++) {
                String s = sc.next();
                for (int j = 1; j <= N; j++) {
                    maze[i][j] = s.charAt(j - 1);
                }
            }
            moveCount = 0;
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= N; j++) {
                    visited[i][j] = 0;
                }
            }
            bfs(1, 1);
            System.out.println(moves);
        }
    }
}

