// COMPLETE, RUNNABLE JavaScript code
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MAX_N = 1000;
const MAX_MOVES = MAX_N * (MAX_N + 7);
const maze = Array(MAX_N + 1).fill(0).map(() => Array(MAX_N + 1).fill(''));
const moves = Array(MAX_MOVES + 1).fill('');
const visited = Array(MAX_N + 1).fill(0).map(() => Array(MAX_N + 1).fill(0));
let moveCount = 0;

function bfs(x, y) {
    const q = [[x, y]];
    visited[x][y] = 1;

    while (q.length > 0) {
        [x, y] = q.shift();

        if (x > 1 && maze[x - 1][y] === '.' && !visited[x - 1][y]) {
            q.push([x - 1, y]);
            visited[x - 1][y] = 1;
            moves[moveCount] = 'U';
            moveCount++;
        }
        if (x < MAX_N && maze[x + 1][y] === '.' && !visited[x + 1][y]) {
            q.push([x + 1, y]);
            visited[x + 1][y] = 1;
            moves[moveCount] = 'D';
            moveCount++;
        }
        if (y > 1 && maze[x][y - 1] === '.' && !visited[x][y - 1]) {
            q.push([x, y - 1]);
            visited[x][y - 1] = 1;
            moves[moveCount] = 'L';
            moveCount++;
        }
        if (y < MAX_N && maze[x][y + 1] === '.' && !visited[x][y + 1]) {
            q.push([x, y + 1]);
            visited[x][y + 1] = 1;
            moves[moveCount] = 'R';
            moveCount++;
        }
    }
}

const T = parseInt(input[idx++]);
for (let i = 0; i < T; i++) {
    const N = parseInt(input[idx++]);
    for (let j = 1; j <= N; j++) {
        const s = input[idx++];
        for (let k = 1; k <= N; k++) {
            maze[j][k] = s[k - 1];
        }
    }
    moveCount = 0;
    for (let j = 1; j <= N; j++) {
        for (let k = 1; k <= N; k++) {
            visited[j][k] = 0;
        }
    }
    bfs(1, 1);
    console.log(moves.slice(0, moveCount).join(''));
}

